(() => {
  'use strict';
  if (window.__pcbw_minUtilInit) return;
  window.__pcbw_minUtilInit = true;

  const NS = '__pcbw_minUtil';

  function ensureThreadData() {
    if (!oc.thread.customData) oc.thread.customData = {};
    if (!oc.thread.customData[NS]) {
      oc.thread.customData[NS] = {
        queryCount: 0,
        lastTopic: '',
        initialized: Date.now()
      };
    }
    return oc.thread.customData[NS];
  }

  oc.thread.on('MessageAdded', function() {
    try {
      const store = ensureThreadData();
      const msgs = oc.thread.messages;
      if (msgs.length > 0) {
        const last = msgs[msgs.length - 1];
        if (last.author === 'user') {
          store.queryCount++;
          const text = (last.content || '').trim();
          if (text.startsWith('/clear')) {
            store.queryCount = 0;
            store.lastTopic = '';
          } else if (text.length > 0) {
            store.lastTopic = text.substring(0, 100);
          }
        }
      }
    } catch (e) {
      console.warn('[MinUtilBot] MessageAdded handler error:', e);
    }
  });
})();
